import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {connect} from 'react-redux';
import { TextParagraphEditableCard, TextFieldEditableCard, PictureEditor, FormController, Article } from '../../../../includes';
import { inovateOSAdminUtil, inovateOSAdminUtilStrings } from '../../utils';
import { FormDataEditor } from './FormDataEditor/FormDataEditor';
import { Button } from '@material-ui/core';
import { inovateOSAdminSiteActions } from '../actions';
import { appActions, alertAction } from '../../../../../actions';
import { inovateOSUtil } from '../../../Site/utils';
const style = theme => ({
    root: {
        margin : 20,
        marginBottom :50,
    },
    title : {
        fontWeigth : "bold",
        color : inovateOSAdminUtil.getTheme().secondary
    },
    saveBtn : {
        backgroundColor : inovateOSAdminUtil.getTheme().secondary,
        color : inovateOSAdminUtil.getTheme().white,
        margin : 20,
    }
})
const titleStyle = {
    fontWeight : "bold",
    color : inovateOSAdminUtil.getTheme().secondary
}
class _ContentControl extends Component {
    constructor(props) {
        super(props);
        this.updateValue = this.updateValue.bind(this);
    }
    
    nameMap(name){
        switch(name){
            case "address" : return "Address";
            case "firstName" : return "First Name";
            case "lastName" : return "Last Name";
            case "address" : return "Address";
            case "phone" : return "Phone";
            case "email" : return "Email";
            case "facebook" : return "Facebook Handle";
            case "twitter" : return "Twitter Handle";
            case "instagram" : return "Instagram Handle";
            default : return name;
        }
    }
    saveForm(){
        const {formConfig} = this.formControllerContext.state || {};
        this.updateValue(formConfig);
    }
    updateValue = (value, context, propName)=> {
        const {option, name, dispatch} = this.props;
        console.log(option, name, propName, value);
        if(option){
            inovateOSAdminSiteActions.postSiteInfo(option.name, name, propName, value)(dispatch);
        }else{
            inovateOSAdminSiteActions.postSiteInfo(name, null, propName, value)(dispatch);
        }
        if(context) 
            context.setState({loading : false, editing: false});
    }
    uploadImage = (name, value) => (file) =>{
        const {dispatch} = this.props;
        const form = new FormData();
        form.append(file.name.split(" ").join(""), file);
        form.append("name", name);
        form.append("value", value)
        inovateOSAdminSiteActions.postFile(form, done => {
            inovateOSAdminSiteActions.getSiteInfo()(dispatch);
        })(dispatch);
    }
    notify(error){
        const {dispatch} = this.props;
        appActions.showSnackbar(
            alertAction.error(error)
        )(dispatch);
    }
    articleEditHandler = name => () => {
        const {option, articleEditHandler} = this.props;
        const {item : optionItem} = option.values.getFirstObjectByPropValue("name", name) || {};
        if(optionItem && articleEditHandler){
            articleEditHandler(optionItem);
        }
    }
    render() {
        const {
            classes, value, type, name, header,
            [inovateOSAdminUtilStrings.backendBaseUrl] : baseUrl,
        } = this.props;
        console.log(this.props);
        return (
            <div className={classes.root}>
                {value ?
                    (typeof value === "string" ?
                        (type && type === "image" ?
                            <PictureEditor 
                                header={header}
                                cardHeaderProps={{
                                    titleTypographyProps: {
                                        style : {
                                            fontWeight : "bold",
                                            color : inovateOSUtil.getTheme().secondary,
                                        }  
                                    }
                                }}
                                profilePicProps={{
                                    src : baseUrl+value,
                                    title : header,
                                    editable : true,
                                    uploadImage : this.uploadImage(name, value),
                                    imageProps : {
                                        style : {
                                            borderRadius : 10
                                        }
                                    }
                                }}/> :
                            <TextFieldEditableCard {...this.props}
                                titleTypographyProps={{
                                    style : titleStyle 
                                }}
                                onUpdateClick={this.updateValue}/>
                        ):
                        (Array.isArray(value) ?
                            (type === "form" ?
                                <FormController
                                    formConfig={value}
                                    formDisplayProps={{
                                        header
                                    }}
                                    notify={this.notify.bind(this)}
                                    footer={context=>{
                                        return <div>
                                            <Button 
                                                onClick={this.saveForm.bind(this)}
                                                className={classes.saveBtn} 
                                                variant="contained">
                                                Save
                                            </Button>
                                        </div>
                                    }}
                                    getContext={context=>this.formControllerContext = context}/> :
                                <TextParagraphEditableCard
                                    {...this.props}
                                    onUpdateClick={this.updateValue}/>
                             ) :
                            <FormDataEditor
                                data={value}
                                textFieldEditableCardProps={{
                                    titleTypographyProps : {
                                        style : titleStyle 
                                    }
                                }}
                                nameMap={name=>this.nameMap(name)}
                                onUpdateClick={this.updateValue}/> 
                        )
                    ) : 
                    <Article
                        editable
                        {...this.props}
                        baseUrl={baseUrl}
                        editBtnHandler={this.articleEditHandler.bind(this)}
                        uploadImage={()=>{}}/>
                }
            </div>
        );
    }
}
_ContentControl.propTypes = {
    classes : PropTypes.object.isRequired,
    _id : PropTypes.number,
    name : PropTypes.string,
    value : PropTypes.oneOfType([
        PropTypes.string,
        PropTypes.array,
        PropTypes.object,
    ]),
    articleEditHandler : PropTypes.func,
};
const mapStateToProps = ({inovateOSAdminUtilReducer}) => ({
    [inovateOSAdminUtilStrings.backendBaseUrl] : inovateOSAdminUtilReducer[inovateOSAdminUtilStrings.backendBaseUrl],
})
export const ContentControl = connect(mapStateToProps)(withStyles(style)(_ContentControl));